interface ButtonProps {
  label: string
  onClick?: () => void
  disabled?: boolean
  ariaLabel?: string
}

export const Button = ({ label, onClick, disabled = false, ariaLabel }: ButtonProps) => (
  <button
    type="button"
    onClick={onClick}
    disabled={disabled}
    aria-label={ariaLabel || label}
    aria-disabled={disabled}
  >
    {label}
  </button>
)
